import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Login.css';

function Login() {
  const [debugInfo, setDebugInfo] = useState({});
  const [cookies, setCookies] = useState('');
  const [formData, setFormData] = useState({
    login: '',
    password: ''
  });
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    updateCookies();
  }, []);

  const updateCookies = () => {
    const cookiesString = document.cookie || 'No cookies';
    setCookies(cookiesString);

    const allCookies = {};
    document.cookie.split(';').forEach(cookie => {
      const [key, value] = cookie.trim().split('=');
      if (key) allCookies[key] = value;
    });
    setDebugInfo(prev => ({...prev, allCookies}));
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleLogin = async () => {
    setIsLoading(true);
    try {
      const response = await fetch('http://localhost:5000/login', {
        method: 'POST',
        credentials: 'include',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      setDebugInfo(prev => ({
        ...prev,
        loginStatus: response.status,
        loginResponse: data,
        timestamp: new Date().toISOString()
      }));

      if (response.ok) {
        updateCookies();
        // Перенаправляем на /table после успешной авторизации
        setTimeout(() => {
          navigate('/table');
        }, 500); // Небольшая задержка для UX
      } else {
        alert(`Login failed: ${data.message || 'Unknown error'}`);
      }
    } catch (error) {
      setDebugInfo(prev => ({...prev, loginError: error.message}));
      alert(`Login error: ${error.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  const testRequest = async () => {
    try {
      const response = await fetch('http://localhost:5000/table', {
        credentials: 'include'
      });

      const data = await response.json();

      setDebugInfo(prev => ({
        ...prev,
        testStatus: response.status,
        testResponse: data,
        testHeaders: Object.fromEntries(response.headers.entries())
      }));
    } catch (error) {
      setDebugInfo(prev => ({...prev, testError: error.message}));
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      handleLogin();
    }
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <h2>Login</h2>

        <div className="login-form">
          <div className="form-group">
            <label htmlFor="login">Username</label>
            <input
              id="login"
              type="text"
              name="login"
              value={formData.login}
              onChange={handleInputChange}
              onKeyPress={handleKeyPress}
              placeholder="Enter your username"
              disabled={isLoading}
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              id="password"
              type="password"
              name="password"
              value={formData.password}
              onChange={handleInputChange}
              onKeyPress={handleKeyPress}
              placeholder="Enter your password"
              disabled={isLoading}
            />
          </div>

          <button 
            onClick={handleLogin} 
            className="login-button"
            disabled={isLoading}
          >
            {isLoading ? (
              <>
                <span className="spinner"></span>
                Logging in...
              </>
            ) : 'Login'}
          </button>

          <div className="demo-credentials">
            <p><strong>Demo credentials:</strong></p>
            <p>Login: admin</p>
            <p>Password: admin</p>
          </div>
        </div>
      </div>

      <div className="debug-panel">
        <h3>Debug Information</h3>

        <div className="debug-section">
          <h4>Cookies:</h4>
          <pre className="cookies-display">{cookies}</pre>
          <button onClick={updateCookies} className="refresh-button">
            Refresh Cookies
          </button>
        </div>

        <div className="debug-section">
          <h4>Test Protected Endpoint:</h4>
          <button onClick={testRequest} className="test-button">
            Test /table endpoint
          </button>
        </div>

        <div className="debug-section">
          <h4>Debug Info:</h4>
          <pre className="debug-info">{JSON.stringify(debugInfo, null, 2)}</pre>
        </div>

        <div className="quick-test">
          <h4>Quick Test:</h4>
          <button onClick={() => {
            fetch('http://localhost:5000/login', {
              method: 'POST',
              credentials: 'include',
              headers: {'Content-Type': 'application/json'},
              body: JSON.stringify({login: 'admin', password: 'admin'})
            })
            .then(res => res.json())
            .then(data => {
              setDebugInfo(prev => ({...prev, quickTest: data}));
              if (data.success) {
                updateCookies();
                setTimeout(() => navigate('/table'), 500);
              }
            })
            .catch(console.error);
          }}>
            Auto Login (admin/admin)
          </button>
        </div>
      </div>
    </div>
  );
}

export default Login;
